20	func TestDecodeTokenWithExpiration(t *testing.T) {
21		tests := []struct {
22			name      string
23			encoded   string
24			wantToken string
25			wantZero  bool  // if true, expect time.Time zero value
26			wantUnix  int64 // checked only when wantZero is false
27		}{
28			{
29				name:      "token with pipe-separated unix timestamp",
30				encoded:   "mytoken|12345",
31				wantToken: "mytoken",
32				wantUnix:  12345,
33			},
34			{
35				name:      "plain token without pipe",
36				encoded:   "plain-token",
37				wantToken: "plain-token",
38				wantZero:  true,
39			},
40			{
41				name:      "empty string",
42				encoded:   "",
43				wantToken: "",
44				wantZero:  true,
45			},
46			{
47				name:      "pipe with non-numeric suffix falls back to full string",
48				encoded:   "tok|notanumber",
49				wantToken: "tok|notanumber",
50				wantZero:  true,
51			},
52			{
53				name:      "multiple pipes uses last one",
54				encoded:   "a|b|99999",
55				wantToken: "a|b",
56				wantUnix:  99999,
57			},
58		}
59	
60		for _, tt := range tests {
61			t.Run(tt.name, func(t *testing.T) {
62				token, ts := decodeTokenWithExpiration(tt.encoded)
63				if token != tt.wantToken {
64					t.Errorf("token = %q, want %q", token, tt.wantToken)
65				}
66				if tt.wantZero {
67					if !ts.IsZero() {
68						t.Errorf("expected zero time, got %v", ts)
69					}
70				} else {
71					if ts.Unix() != tt.wantUnix {
72						t.Errorf("timestamp = %d, want %d", ts.Unix(), tt.wantUnix)
73					}
74				}
75			})
76		}
77	}
78	
79	func TestTokenExpiredOrExpiring(t *testing.T) {
80		tests := []struct {
81			name      string
82			expiresAt time.Time
83			want      bool
84		}{
85			{
86				name:      "zero time is treated as expired",
87				expiresAt: time.Time{},
88				want:      true,
89			},
