if cfg.Progress {
	out := cfg.progressOut
	if out == nil {
		out = os.Stderr
	}
	// Render only when the destination is a real terminal. Pipes,
	// log files, and CI captures get nothing rather than a flood
	// of '\r'-prefixed control sequences.
	if out != os.Stderr || stderrIsTTY() {
