func TestRequestInfoRefs_OnUnauthorizedRetriesWithHelperCredentials(t *testing.T) {
	helper := &fakeCredentialHelper{lookupUser: "alice", lookupPass: "s3cret", lookupOK: true}

	var authHeaders []string
